                    if typ == 'v' and c2 == pos:
                        output[r2, c2] = 2

        elif typ == 'h':
            # Horizontal axis at row pos
            axis_7_cols = sorted([c for r, c in axis_cells if r == pos])

            if axis_7_cols:
